import React, { useEffect, useState } from 'react';
import { Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
} from 'chart.js';
import api from '../services/api';
import { CarbonTrend, Prediction } from '../types';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

export const Dashboard: React.FC = () => {
  const [metrics, setMetrics] = useState<any>(null);
  const [trends, setTrends] = useState<CarbonTrend[]>([]);
  const [predictions, setPredictions] = useState<Prediction[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [metricsRes, trendsRes, predictionsRes] = await Promise.all([
        api.get('/analytics/dashboard'),
        api.get('/detection/emissions-trend?days=30'),
        api.get('/prediction/future-emissions?days=30')
      ]);

      setMetrics(metricsRes.data);
      setTrends(trendsRes.data);
      setPredictions(predictionsRes.data);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div>Loading dashboard...</div>;

  const trendChartData = {
    labels: trends.map(t => new Date(t.date).toLocaleDateString()),
    datasets: [
      {
        label: 'Daily Emissions (kg CO2e)',
        data: trends.map(t => t.total_emissions),
        borderColor: 'rgb(75, 192, 192)',
        backgroundColor: 'rgba(75, 192, 192, 0.1)',
        tension: 0.4
      }
    ]
  };

  const predictionChartData = {
    labels: predictions.map(p => new Date(p.date).toLocaleDateString()),
    datasets: [
      {
        label: 'Predicted Emissions (kg CO2e)',
        data: predictions.map(p => p.predicted_emissions),
        borderColor: 'rgb(255, 159, 64)',
        backgroundColor: 'rgba(255, 159, 64, 0.1)',
        tension: 0.4
      }
    ]
  };

  return (
    <div className="w-full bg-gradient-to-br from-blue-50 to-green-50 p-8 rounded-lg">
      <h1 className="text-4xl font-bold text-gray-800 mb-8">Carbon Footprint Dashboard</h1>

      {/* Metrics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Total Emissions</p>
          <p className="text-3xl font-bold text-green-600">{metrics?.total_emissions || 0}</p>
          <p className="text-xs text-gray-500">kg CO2e</p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Total Detections</p>
          <p className="text-3xl font-bold text-blue-600">{metrics?.total_detections || 0}</p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Average per Detection</p>
          <p className="text-3xl font-bold text-orange-600">{metrics?.average_emissions || 0}</p>
          <p className="text-xs text-gray-500">kg CO2e</p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Top Detected</p>
          <p className="text-2xl font-bold text-purple-600">{metrics?.top_detected_object || 'N/A'}</p>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-lg shadow-lg">
          <h2 className="text-xl font-bold text-gray-800 mb-4">Historical Trends (Past 30 Days)</h2>
          <Line data={trendChartData} options={{ responsive: true }} />
        </div>

        <div className="bg-white p-6 rounded-lg shadow-lg">
          <h2 className="text-xl font-bold text-gray-800 mb-4">Future Predictions (Next 30 Days)</h2>
          <Line data={predictionChartData} options={{ responsive: true }} />
        </div>
      </div>
    </div>
  );
};
